export interface Topic3EnvelopeV1 {
  /** Frozen public Envelope wire version. */
  "schema_version"?: "topic3.envelope.v1"
  /** Globally unique envelope identity generated at message creation. */
  "envelope_id": string
  /** Stable event name from the Topic 3 event catalog. */
  "event_type": string
  /** Command, event, result, or standardized error receipt. */
  "message_kind": MessageKind
  /** Tenant boundary sourced only from authenticated server context. */
  "tenant_id": string
  /** Learning-session identity from the frozen Topic 1/2 session model. */
  "session_id": string
  /** Tokenized user or service subject reference; never raw PII. */
  "subject_ref": string
  /** Root workflow correlation identity preserved across agents. */
  "correlation_id": string
  /** Envelope identity that directly caused this message. */
  "causation_id"?: string | null
  /** Monotonic sequence inside the partition key, assigned by the producer. */
  "sequence": number
  /** Ordering partition, normally tenant/session/candidate identity. */
  "partition_key": string
  /** Producing agent/service provenance supplied by runtime infrastructure. */
  "producer": ProducerMetadataV1
  /** At-least-once delivery, retry, priority, and expiry metadata. */
  "delivery": DeliveryMetadataV1
  /** Optional blueprint/candidate/block identity for resource messages. */
  "resource"?: ResourceMetadataV1 | null
  /** Distributed trace identity generated or propagated by infrastructure. */
  "trace_id": string
  /** Current trace span identity when tracing is enabled. */
  "span_id"?: string | null
  /** UTC message creation time from the producing service clock. */
  "created_at": string
  /** Standard error receipt, required only when message_kind is ERROR. */
  "error"?: ErrorReceiptV1 | null
  /** Agent-specific versioned payload; validated by the owning payload schema. */
  "payload"?: {  }
}

